const source = $input.first().json.body ?? $input.first().json;
function text(value) { return typeof value === 'string' ? value.trim() : ''; }
function object(value) { return value && typeof value === 'object' && !Array.isArray(value) ? value : {}; }
function firstText(...values) { for (const value of values) { const result = text(value); if (result) return result; } return ''; }
function isUrl(value) { return /^https?:\/\//i.test(text(value)); }
const career = object(source.careerReview || source.career || source.jobApplicationReview);
const jd = object(career.jobDescription || source.jobDescription || source.jd);
const cv = object(career.cv || source.cv || source.resume);
const requestId = firstText(source.requestId, career.requestId) || `career-review-${Date.now()}`;
const traceId = firstText(source?.metadata?.traceId, career.traceId);
const title = firstText(career.title, source.title, jd.title, `${firstText(career.company, source.company, jd.company) || 'career'} ${firstText(career.role, source.role, jd.role, jd.title) || 'review'}`);
const jobDescriptionText = firstText(jd.text, jd.markdown, jd.source, source.jobDescriptionText, source.jdText, source.source);
const jobDescriptionUrl = isUrl(jd.url) ? text(jd.url) : (isUrl(jd.downloadUrl) ? text(jd.downloadUrl) : (isUrl(source.jobDescriptionUrl) ? text(source.jobDescriptionUrl) : (isUrl(source.jdUrl) ? text(source.jdUrl) : '')));
const cvText = firstText(cv.text, cv.markdown, cv.source, source.cvText, source.resumeText);
const cvUrl = isUrl(cv.url) ? text(cv.url) : (isUrl(cv.downloadUrl) ? text(cv.downloadUrl) : (isUrl(cv.assetUrl) ? text(cv.assetUrl) : (isUrl(source.cvUrl) ? text(source.cvUrl) : (isUrl(source.resumeUrl) ? text(source.resumeUrl) : ''))));
const errors = [];
if (!jobDescriptionText && !jobDescriptionUrl) errors.push('jobDescription.text or jobDescription.url is required');
if (!cvText && !cvUrl) errors.push('cv.text or cv.url is required');
if (errors.length) {
  return [{ json: { requestId, status: 'failed', route: 'error', responseCode: 400, errorCode: 'INVALID_CAREER_REVIEW_REQUEST', message: errors.join('; '), responseBody: { accepted: false, requestId, status: 'failed', errorCode: 'INVALID_CAREER_REVIEW_REQUEST', message: errors.join('; ') } } }];
}
const jobId = `job_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
const workerBaseUrl = String($env.MEDIA_WORKER_BASE_URL || 'https://media-worker.techmatrx.com').trim().replace(/\/+$/, '');
const dispatchUrl = `${workerBaseUrl}/jobs`;
const profile = 'career_jd_cv_review';
const metadata = object(source.metadata);
const payload = {
  careerReview: {
    title,
    company: firstText(career.company, source.company, jd.company),
    role: firstText(career.role, source.role, jd.role, jd.title),
    jobDescription: { text: jobDescriptionText, url: jobDescriptionUrl },
    cv: { text: cvText, url: cvUrl },
    sourcePolicy: 'cv-and-current-request-only',
    language: firstText(career.language, source.language, 'en'),
    notes: firstText(career.notes, source.notes)
  },
  metadata: {
    ...metadata,
    source: metadata.source || 'openclaw-career-review-submit-v1',
    traceId: traceId || undefined,
    requestedProfile: profile,
    internalProfile: profile,
    productWorkflow: 'career-jd-cv-review-submit-v1',
    delivery: object(source.delivery || metadata.delivery)
  }
};
return [{ json: { requestId, jobId, profile, dispatchUrl, route: 'continue', responseCode: 202, workerDispatchBody: { jobId, requestId, profile, payload }, responseBody: { accepted: true, requestId, jobId, profile, status: 'queued', message: 'Career JD/CV review queued' } } }];
